var raw = $input.first().json;
var body = raw.body || raw;
var tenantId = String(body.tenantId || '');
var exerciceId = body.exerciceId ? String(body.exerciceId) : null;
var page = parseInt(body.page || '1', 10);
var limit = parseInt(body.limit || '50', 10);

var UUID_RE = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;

if (!tenantId || !UUID_RE.test(tenantId)) {
  throw new Error('tenantId requis et doit être un UUID valide');
}

if (exerciceId && !UUID_RE.test(exerciceId)) {
  throw new Error('exerciceId doit être un UUID valide si fourni');
}

if (page < 1) page = 1;
if (limit < 1) limit = 50;
if (limit > 500) limit = 500;

var offset = (page - 1) * limit;

return [{
  json: {
    tenantId: tenantId,
    exerciceId: exerciceId,
    page: page,
    limit: limit,
    offset: offset
  }
}];

var countData = $('05. Count').first();
var listData = $('06. List').all();
var total = countData && countData.json ? parseInt(countData.json.count || '0', 10) : 0;
var page = $json.page;
var limit = $json.limit;
var totalPages = Math.ceil(total / limit) || 1;

var fichiers = listData.map(function(item) {
  var f = item.json;
  return {
    id: f.id,
    exerciceId: f.exercice_id,
    nomFichier: f.nom_fichier,
    format: f.format,
    nombreEcritures: f.nombre_ecritures,
    nombreLignes: f.nombre_lignes,
    hashSha256: f.hash_sha256,
    statut: f.statut,
    dateGeneration: f.date_generation,
    dateValidation: f.date_validation,
    createdAt: f.created_at
  };
});

return [{
  json: {
    success: true,
    fichiers: fichiers,
    count: fichiers.length,
    total: total,
    page: page,
    totalPages: totalPages
  }
}];
